#!/usr/bin/perl
use strict;
use warnings;
use CGI qw(:standard escapeHTML);

my $q = CGI->new;
my $log_dir = '/var/log';
my $filename = $q->param('logfile') // '';

print $q->header('text/html; charset=UTF-8');
print "<!DOCTYPE html><html><head><title>Log Viewer</title></head><body>";
print "<h1>Log Viewer</h1>";

if ($filename eq '') {
    print "<p>No logfile specified.</p>";
    print "</body></html>";
    exit;
}

if ($filename =~ m{[^\w.\-]}) {
    print "<p>Invalid logfile name.</p>";
    print "</body></html>";
    exit;
}

my $path = "$log_dir/$filename";

if (!-f $path) {
    print "<p>Log file not found.</p>";
    print "</body></html>";
    exit;
}

if (!open(my $fh, '<', $path)) {
    print "<p>Unable to open log file.</p>";
    print "</body></html>";
    exit;
}

print "<h2>" . escapeHTML($filename) . "</h2>";
print "<pre>";

while (my $line = <$fh>) {
    print escapeHTML($line);
}

close($fh);

print "</pre>";
print "</body></html>";